using SkiaSharp;
using System;

Console.WriteLine($"SkiaSharp version: {typeof(SKBitmap).Assembly.GetName().Version}");

var path = new SKPath();
path.AddRect(new SKRect(-25, -25, 25, 25));
float offsetX = 200f, offsetY = 150f;
path.Transform(SKMatrix.CreateTranslation(offsetX, offsetY));
Console.WriteLine($"Center BEFORE rotation: ({path.Bounds.MidX}, {path.Bounds.MidY})");

path.Transform(SKMatrix.CreateRotationDegrees(45.0f));
Console.WriteLine($"Center AFTER rotation (no pivot): ({path.Bounds.MidX}, {path.Bounds.MidY})");

float dist = MathF.Sqrt(MathF.Pow(path.Bounds.MidX - offsetX, 2) + MathF.Pow(path.Bounds.MidY - offsetY, 2));
Console.WriteLine($"Distance moved: {dist:F2}");
Console.WriteLine(dist > 1.0f ? "REPRODUCED: path swung around origin" : "NOT REPRODUCED: stayed in place");

var path2 = new SKPath();
path2.AddRect(new SKRect(-25, -25, 25, 25));
path2.Transform(SKMatrix.CreateTranslation(offsetX, offsetY));
path2.Transform(SKMatrix.CreateRotationDegrees(45.0f, offsetX, offsetY));
float dist2 = MathF.Sqrt(MathF.Pow(path2.Bounds.MidX - offsetX, 2) + MathF.Pow(path2.Bounds.MidY - offsetY, 2));
Console.WriteLine($"With pivot - distance moved: {dist2:F2}");
Console.WriteLine(dist2 < 1.0f ? "Pivot overload rotates in place correctly" : "Unexpected: pivot overload also moved");
Console.WriteLine("SUCCESS: test completed");
